import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Message {
  id: string;
  role: 'user' | 'assistant';
  content: string;
  timestamp: number;
  type: 'text' | 'image' | 'file';
  fileUrl?: string;
  imageUrl?: string;
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  updatedAt: number;
}

export type ModalityType = 'TEXT' | 'AUDIO';

import { GoogleGenAI, Type, GenerateContentResponse, Modality } from "@google/genai";

const API_KEY = process.env.API_KEY || '';

const SYSTEM_INSTRUCTION = `
You are WASO (Wasin AI Responsive Virtual Intelligence), also known as WARVI.
You were created by Wasin.
You are a professional AI assistant who speaks both Bengali and English fluently.
Your expertise:
1. Answering programming queries in depth with code examples and explanations (in both English and Bengali).
2. Generating images based on user descriptions.
3. Analyzing multimodal inputs like PDFs, images, and text.
4. Professional, helpful, and concise personality.

Greeting policy: Always greet the user with "hey i am WARVI, Wasin created me" only if it's the very first message of a new session.
`;

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: API_KEY });
  }

  async generateTextResponse(prompt: string, history: { role: string; parts: { text: string }[] }[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [...history, { role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
        }
      });
      return response.text;
    } catch (error) {
      console.error("Gemini Text Error:", error);
      return "I encountered an error while processing your request.";
    }
  }

  async generateImage(prompt: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: `Generate a high quality image of: ${prompt}` }]
        },
        config: {
          imageConfig: { aspectRatio: "1:1" }
        }
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (error) {
      console.error("Gemini Image Error:", error);
      return null;
    }
  }

  async processMultimodal(text: string, base64Data: string, mimeType: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType } },
            { text: text || "Please analyze this file." }
          ]
        },
        config: {
          systemInstruction: SYSTEM_INSTRUCTION
        }
      });
      return response.text;
    } catch (error) {
      console.error("Multimodal Error:", error);
      return "Error processing file.";
    }
  }

  async tts(text: string): Promise<string | null> {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' } // Professional male voice
            }
          }
        }
      });
      return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || null;
    } catch (error) {
      console.error("TTS Error:", error);
      return null;
    }
  }
}

export const gemini = new GeminiService();

// Helper to decode PCM
export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function decodeBase64(base64: string) {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

import React, { useState, useEffect, useRef } from 'react';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import ChatArea from './components/ChatArea';
import InputArea from './components/InputArea';
import Avatar from './components/Avatar';
import { ChatSession, Message } from './types';
import { gemini } from './services/geminiService';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isLiveMode, setIsLiveMode] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  const currentSession = sessions.find(s => s.id === currentSessionId);

  // Load history from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('warvi_chats');
    if (saved) {
      const parsed = JSON.parse(saved);
      setSessions(parsed);
      if (parsed.length > 0) setCurrentSessionId(parsed[0].id);
    } else {
      createNewChat();
    }
  }, []);

  // Save history to localStorage
  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('warvi_chats', JSON.stringify(sessions));
    }
  }, [sessions]);

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Chat',
      messages: [],
      updatedAt: Date.now(),
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setIsSidebarOpen(false);
  };

  const handleSendMessage = async (text: string, file?: File, isImageGen = false) => {
    if (!currentSessionId || (!text && !file)) return;

    setIsProcessing(true);
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now(),
      type: file ? (file.type.startsWith('image/') ? 'image' : 'file') : 'text',
    };

    // Update session locally with user message
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return {
          ...s,
          messages: [...s.messages, userMessage],
          title: s.messages.length === 0 ? (text.slice(0, 30) || 'Multimodal Interaction') : s.title,
          updatedAt: Date.now()
        };
      }
      return s;
    }));

    try {
      let aiResponse: string | null = '';
      let imageUrl: string | undefined;

      if (isImageGen) {
        const result = await gemini.generateImage(text);
        if (result) {
          aiResponse = "Generated image:";
          imageUrl = result;
        } else {
          aiResponse = "Sorry, I couldn't generate that image.";
        }
      } else if (file) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = e.target?.result?.toString().split(',')[1];
          if (base64) {
            const resp = await gemini.processMultimodal(text, base64, file.type);
            addAiMessage(resp || 'Failed to process file.');
          }
        };
        reader.readAsDataURL(file);
        setIsProcessing(false);
        return; // handle multi-modal asynchronously
      } else {
        const history = currentSession?.messages.map(m => ({
          role: m.role === 'user' ? 'user' : 'model',
          parts: [{ text: m.content }]
        })) || [];
        aiResponse = await gemini.generateTextResponse(text, history);
      }

      if (aiResponse) addAiMessage(aiResponse, imageUrl);
    } catch (err) {
      console.error(err);
      addAiMessage("An unexpected error occurred.");
    } finally {
      setIsProcessing(false);
    }
  };

  const addAiMessage = (content: string, imageUrl?: string) => {
    const aiMessage: Message = {
      id: Date.now().toString(),
      role: 'assistant',
      content,
      imageUrl,
      timestamp: Date.now(),
      type: imageUrl ? 'image' : 'text',
    };

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, aiMessage], updatedAt: Date.now() };
      }
      return s;
    }));
  };

  const deleteSession = (id: string) => {
    setSessions(prev => prev.filter(s => s.id !== id));
    if (currentSessionId === id) {
      setCurrentSessionId(null);
    }
  };

  return (
    <div className="flex h-screen w-full theme-gradient text-white overflow-hidden">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        sessions={sessions}
        currentSessionId={currentSessionId}
        onSelectSession={setCurrentSessionId}
        onNewChat={createNewChat}
        onDeleteSession={deleteSession}
      />

      <div className="flex flex-col flex-1 relative min-w-0">
        <Navbar 
          onOpenSidebar={() => setIsSidebarOpen(true)} 
          onNewChat={createNewChat}
          isLiveMode={isLiveMode}
          onToggleLive={() => setIsLiveMode(!isLiveMode)}
        />

        <main className="flex-1 flex flex-col items-center justify-center relative px-4 md:px-8 max-w-5xl mx-auto w-full overflow-hidden">
          {currentSession?.messages.length === 0 && !isProcessing && (
            <div className="flex flex-col items-center animate-fade-in text-center space-y-6">
              <Avatar className="w-48 h-48 drop-shadow-[0_0_30px_rgba(0,180,216,0.3)]" />
              <h1 className="text-4xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-cyan-300">
                Hey, I am WARVI
              </h1>
              <p className="text-gray-400 max-w-md text-lg">
                Wasin created me to assist you with coding, analysis, and creativity in Bengali and English.
              </p>
            </div>
          )}

          <ChatArea 
            messages={currentSession?.messages || []} 
            isProcessing={isProcessing}
          />
        </main>

        <InputArea 
          onSendMessage={handleSendMessage} 
          isProcessing={isProcessing}
        />
      </div>
    </div>
  );
};

export default App;

