export default Sidebar;

import React, { useEffect, useRef, useState } from 'react';
import { Volume2, VolumeX, Bot, User, Loader2 } from 'lucide-react';
import { Message } from '../types';
import { gemini, decodeAudioData, decodeBase64 } from '../services/geminiService';

interface ChatAreaProps {
  messages: Message[];
  isProcessing: boolean;
}

const ChatArea: React.FC<ChatAreaProps> = ({ messages, isProcessing }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const [playingId, setPlayingId] = useState<string | null>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, isProcessing]);

  const speak = async (message: Message) => {
    if (playingId === message.id) {
      setPlayingId(null);
      return;
    }

    try {
      setPlayingId(message.id);
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const base64Audio = await gemini.tts(message.content);
      if (base64Audio) {
        const audioBuffer = await decodeAudioData(
          decodeBase64(base64Audio),
          audioContextRef.current,
          24000,
          1
        );
        const source = audioContextRef.current.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => setPlayingId(null);
        source.start();
      } else {
        setPlayingId(null);
      }
    } catch (err) {
      console.error(err);
      setPlayingId(null);
    }
  };

  return (
    <div 
      ref={scrollRef}
      className="w-full flex-1 overflow-y-auto custom-scrollbar space-y-6 pt-4 pb-32"
    >
      {messages.map((msg) => (
        <div 
          key={msg.id} 
          className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
        >
          <div className={`flex max-w-[85%] md:max-w-[75%] space-x-3 ${msg.role === 'user' ? 'flex-row-reverse space-x-reverse' : 'flex-row'}`}>
            <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${msg.role === 'user' ? 'bg-[#00b4d8]/20' : 'bg-white/10'}`}>
              {msg.role === 'user' ? <User size={18} className="text-[#00b4d8]" /> : <Bot size={18} className="text-blue-400" />}
            </div>

            <div className="flex flex-col space-y-2">
              <div className={`p-4 rounded-2xl relative group ${
                msg.role === 'user' 
                ? 'bg-blue-600/20 border border-blue-500/20 text-blue-50 rounded-tr-none' 
                : 'bg-white/5 border border-white/5 text-gray-200 rounded-tl-none'
              }`}>
                {msg.imageUrl && (
                  <img 
                    src={msg.imageUrl} 
                    alt="AI Generated" 
                    className="w-full max-w-sm rounded-lg mb-3 shadow-lg border border-white/10" 
                  />
                )}

                <div className="whitespace-pre-wrap leading-relaxed text-[15px]">
                  {msg.content}
                </div>

                {msg.role === 'assistant' && msg.content && (
                  <button 
                    onClick={() => speak(msg)}
                    className="absolute -bottom-10 left-0 p-2 text-gray-500 hover:text-[#00b4d8] transition-colors"
                  >
                    {playingId === msg.id ? <VolumeX size={18} className="animate-pulse" /> : <Volume2 size={18} />}
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      ))}

      {isProcessing && (
        <div className="flex justify-start items-center space-x-3 text-gray-500">
          <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center">
            <Loader2 size={18} className="animate-spin" />
          </div>
          <span className="text-sm font-medium animate-pulse">WARVI is thinking...</span>
        </div>
      )}
    </div>
  );
};

export default ChatArea;

import React, { useState, useRef, useEffect } from 'react';
import { ArrowUp, Mic, Image as ImageIcon, FileUp, X, Sparkles } from 'lucide-react';

interface InputAreaProps {
  onSendMessage: (text: string, file?: File, isImageGen?: boolean) => void;
  isProcessing: boolean;
}

const InputArea: React.FC<InputAreaProps> = ({ onSendMessage, isProcessing }) => {
  const [input, setInput] = useState('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [isImageGenMode, setIsImageGenMode] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = 'en-US'; // Default

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setInput(prev => prev + ' ' + transcript);
        setIsListening(false);
      };

      recognitionRef.current.onerror = () => setIsListening(false);
      recognitionRef.current.onend = () => setIsListening(false);
    }
  }, []);

  const handleSend = () => {
    if ((!input.trim() && !selectedFile) || isProcessing) return;
    onSendMessage(input, selectedFile || undefined, isImageGenMode);
    setInput('');
    setSelectedFile(null);
    setIsImageGenMode(false);
  };

  const toggleListen = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      recognitionRef.current?.start();
      setIsListening(true);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedFile(e.target.files[0]);
    }
  };

  return (
    <div className="w-full fixed bottom-0 left-0 right-0 p-4 md:p-8 flex justify-center z-20 pointer-events-none">
      <div className="w-full max-w-4xl flex flex-col pointer-events-auto">
        {selectedFile && (
          <div className="mb-2 ml-4 flex items-center space-x-2 bg-blue-500/20 text-blue-300 px-3 py-1.5 rounded-full w-fit border border-blue-500/30">
            <span className="text-xs truncate max-w-[200px]">{selectedFile.name}</span>
            <button onClick={() => setSelectedFile(null)} className="hover:text-white">
              <X size={14} />
            </button>
          </div>
        )}

        <div className="relative glass-effect rounded-[28px] shadow-2xl overflow-hidden border border-white/10 group focus-within:border-blue-500/50 transition-all duration-300">
          <div className="flex items-end p-2 md:p-3">
            <div className="flex items-center space-x-1 pl-1 pb-1">
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="p-2 text-gray-400 hover:text-[#00b4d8] hover:bg-white/5 rounded-full transition-all"
                title="Upload file"
              >
                <FileUp size={20} />
              </button>
              <button 
                onClick={() => setIsImageGenMode(!isImageGenMode)}
                className={`p-2 rounded-full transition-all ${isImageGenMode ? 'text-purple-400 bg-purple-500/10' : 'text-gray-400 hover:text-purple-400 hover:bg-white/5'}`}
                title="Toggle Image Generation"
              >
                <Sparkles size={20} />
              </button>
            </div>

            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSend();
                }
              }}
              placeholder={isImageGenMode ? "Describe the image you want to generate..." : "Ask WARVI anything..."}
              className="flex-1 bg-transparent border-none outline-none resize-none py-3 px-4 text-white placeholder-gray-500 max-h-32 text-[15px]"
              rows={1}
            />

            <div className="flex items-center space-x-1 pr-1 pb-1">
              <button 
                onClick={toggleListen}
