export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    // Fixed: Always use process.env.API_KEY directly in the GoogleGenAI constructor.
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async generateTextResponse(prompt: string, history: { role: string; parts: { text: string }[] }[]) {
    try {
      // Fixed: Using gemini-3-pro-preview for complex text tasks like coding.
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [...history, { role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
        }
      });
      return response.text;
    } catch (error) {
      console.error("Gemini Text Error:", error);
      return "I encountered an error while processing your request.";
    }
  }

  async generateImage(prompt: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: `Generate a high quality image of: ${prompt}` }]
        },
        config: {
          imageConfig: { aspectRatio: "1:1" }
        }
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (error) {
      console.error("Gemini Image Error:", error);
      return null;
    }
  }

  async processMultimodal(text: string, base64Data: string, mimeType: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType } },
            { text: text || "Please analyze this file." }
          ]
        },
        config: {
          systemInstruction: SYSTEM_INSTRUCTION
        }
      });
      return response.text;
    } catch (error) {
      console.error("Multimodal Error:", error);
      return "Error processing file.";
    }
  }

  async tts(text: string): Promise<string | null> {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' } // Professional male voice
            }
          }
        }
      });
      return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || null;
    } catch (error) {
      console.error("TTS Error:", error);
      return null;
    }
  }

  connectLive(callbacks: {
    onopen: () => void;
    onmessage: (message: LiveServerMessage) => void;
    onerror: (e: ErrorEvent) => void;
    onclose: (e: CloseEvent) => void;
  }) {
    return this.ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks,
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
        },
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });
  }
}

export const gemini = new GeminiService();

export function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import React, { useEffect, useRef, useState } from 'react';
import { Volume2, VolumeX, Bot, User, Loader2 } from 'lucide-react';
import { Message } from '../types';
// Fixed: Imported 'decode' instead of the non-existent 'decodeBase64'.
import { gemini, decodeAudioData, decode } from '../services/geminiService';

interface ChatAreaProps {
  messages: Message[];
  isProcessing: boolean;
}

const ChatArea: React.FC<ChatAreaProps> = ({ messages, isProcessing }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const [playingId, setPlayingId] = useState<string | null>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, isProcessing]);

  const speak = async (message: Message) => {
    if (playingId === message.id) {
      setPlayingId(null);
      return;
    }

    try {
      setPlayingId(message.id);
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const base64Audio = await gemini.tts(message.content);
      if (base64Audio) {
        // Fixed: Use the manually implemented 'decode' function.
        const audioBuffer = await decodeAudioData(
          decode(base64Audio),
          audioContextRef.current,
          24000,
          1
        );
        const source = audioContextRef.current.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => setPlayingId(null);
        source.start();
      } else {
        setPlayingId(null);
      }
    } catch (err) {
      console.error(err);
      setPlayingId(null);
    }
  };

  return (
    <div 
      ref={scrollRef}
      className="w-full flex-1 overflow-y-auto custom-scrollbar space-y-6 pt-4 pb-32"
    >
      {messages.map((msg) => (
        <div 
          key={msg.id} 
          className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
        >
          <div className={`flex max-w-[85%] md:max-w-[75%] space-x-3 ${msg.role === 'user' ? 'flex-row-reverse space-x-reverse' : 'flex-row'}`}>
            <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${msg.role === 'user' ? 'bg-[#00b4d8]/20' : 'bg-white/10'}`}>
              {msg.role === 'user' ? <User size={18} className="text-[#00b4d8]" /> : <Bot size={18} className="text-blue-400" />}
            </div>

            <div className="flex flex-col space-y-2">
              <div className={`p-4 rounded-2xl relative group ${
                msg.role === 'user' 
                ? 'bg-blue-600/20 border border-blue-500/20 text-blue-50 rounded-tr-none' 
                : 'bg-white/5 border border-white/5 text-gray-200 rounded-tl-none'
              }`}>
                {msg.imageUrl && (
                  <img 
                    src={msg.imageUrl} 
                    alt="AI Generated" 
                    className="w-full max-w-sm rounded-lg mb-3 shadow-lg border border-white/10" 
                  />
                )}

                <div className="whitespace-pre-wrap leading-relaxed text-[15px]">
                  {msg.content}
                </div>

                {msg.role === 'assistant' && msg.content && (
                  <button 
                    onClick={() => speak(msg)}
                    className="absolute -bottom-10 left-0 p-2 text-gray-500 hover:text-[#00b4d8] transition-colors"
                  >
                    {playingId === msg.id ? <VolumeX size={18} className="animate-pulse" /> : <Volume2 size={18} />}
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      ))}

      {isProcessing && (
        <div className="flex justify-start items-center space-x-3 text-gray-500">
          <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center">
            <Loader2 size={18} className="animate-spin" />
          </div>
          <span className="text-sm font-medium animate-pulse">WARVI is thinking...</span>
        </div>
      )}
    </div>
  );
};

