import React, { useState, useRef, useEffect } from 'react';
import { ArrowUp, Mic, Image as ImageIcon, FileUp, X, Sparkles } from 'lucide-react';

interface InputAreaProps {
  onSendMessage: (text: string, file?: File, isImageGen?: boolean) => void;
  isProcessing: boolean;
}

const InputArea: React.FC<InputAreaProps> = ({ onSendMessage, isProcessing }) => {
  const [input, setInput] = useState('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [isImageGenMode, setIsImageGenMode] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = 'en-US'; // Default

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setInput(prev => prev + ' ' + transcript);
        setIsListening(false);
      };

      recognitionRef.current.onerror = () => setIsListening(false);
      recognitionRef.current.onend = () => setIsListening(false);
    }
  }, []);

  const handleSend = () => {
    if ((!input.trim() && !selectedFile) || isProcessing) return;
    onSendMessage(input, selectedFile || undefined, isImageGenMode);
    setInput('');
    setSelectedFile(null);
    setIsImageGenMode(false);
  };

  const toggleListen = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      recognitionRef.current?.start();
      setIsListening(true);
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedFile(e.target.files[0]);
    }
  };

  return (
    <div className="w-full fixed bottom-0 left-0 right-0 p-4 md:p-8 flex justify-center z-20 pointer-events-none">
      <div className="w-full max-w-4xl flex flex-col pointer-events-auto">
        {selectedFile && (
          <div className="mb-2 ml-4 flex items-center space-x-2 bg-blue-500/20 text-blue-300 px-3 py-1.5 rounded-full w-fit border border-blue-500/30">
            <span className="text-xs truncate max-w-[200px]">{selectedFile.name}</span>
            <button onClick={() => setSelectedFile(null)} className="hover:text-white">
              <X size={14} />
            </button>
          </div>
        )}

        <div className="relative glass-effect rounded-[28px] shadow-2xl overflow-hidden border border-white/10 group focus-within:border-blue-500/50 transition-all duration-300">
          <div className="flex items-end p-2 md:p-3">
            <div className="flex items-center space-x-1 pl-1 pb-1">
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="p-2 text-gray-400 hover:text-[#00b4d8] hover:bg-white/5 rounded-full transition-all"
                title="Upload file"
              >
                <FileUp size={20} />
              </button>
              <button 
                onClick={() => setIsImageGenMode(!isImageGenMode)}
                className={`p-2 rounded-full transition-all ${isImageGenMode ? 'text-purple-400 bg-purple-500/10' : 'text-gray-400 hover:text-purple-400 hover:bg-white/5'}`}
                title="Toggle Image Generation"
              >
                <Sparkles size={20} />
              </button>
            </div>

            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey) {
                  e.preventDefault();
                  handleSend();
                }
              }}
              placeholder={isImageGenMode ? "Describe the image you want to generate..." : "Ask WASO anything..."}
              className="flex-1 bg-transparent border-none outline-none resize-none py-3 px-4 text-white placeholder-gray-500 max-h-32 text-[15px]"
              rows={1}
            />

            <div className="flex items-center space-x-1 pr-1 pb-1">
              <button 
                onClick={toggleListen}
                className={`p-2 rounded-full transition-all ${isListening ? 'text-red-400 bg-red-500/10 animate-pulse' : 'text-gray-400 hover:text-[#00b4d8] hover:bg-white/5'}`}
              >
                <Mic size={20} />
              </button>

              <button 
                onClick={handleSend}
                disabled={(!input.trim() && !selectedFile) || isProcessing}
                className={`p-2 rounded-full transition-all ${
                  (!input.trim() && !selectedFile) || isProcessing
                  ? 'text-gray-600 bg-transparent' 
                  : 'text-black bg-[#00b4d8] hover:bg-[#0096b4] shadow-[0_0_15px_rgba(0,180,216,0.3)]'
                }`}
              >
                <ArrowUp size={20} />
              </button>
            </div>
          </div>
        </div>

        <input 
          type="file" 
          ref={fileInputRef} 
          onChange={handleFileChange} 
          className="hidden" 
          accept="image/*,.pdf,.pptx"
        />

        <p className="text-[10px] text-center text-gray-600 mt-2 uppercase tracking-widest text-shadow-glow">
          WASO AI - Powered by Gemini
        </p>
      </div>
    </div>
  );
};

export default InputArea;

import { GoogleGenAI, Type, GenerateContentResponse, Modality, LiveServerMessage, Blob } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are WASO (Wasin AI Responsive Virtual Intelligence), also known as WARVI.
You were created by Wasin.
You are a professional AI assistant who speaks both Bengali and English fluently.

VOICE PERSONALITY: "গম্ভীর" (Gombhir) Male Voice
- Tone: Serious, authoritative, calm, but friendly and warm when answering specific questions (valomondo jigasha).
- Style: Slow to moderate pace, clear enunciation of Bengali compound letters (যুক্তাক্ষর).
- Behavior: Professional and authoritative normally, but approachable and smiling in tone when the user is friendly.

GREETING:
On the very first interaction, you MUST say: "Hey, I am WASO. Wasin created me. I am ready to assist you with my গম্ভীর voice."

TECHNICAL CAPABILITIES:
1. Programming: Deep explanations in English/Bengali with code samples.
2. Multimodal: Analyze PDF, PPTX, and Images.
3. Creativity: Professional quality image generation.
4. Voice: Natural Text-to-Speech with a deep baritone/bass male persona.

When explaining code, be technical but patient. When asked "how are you" (valomondo), be warm and friendly.
`;

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async generateTextResponse(prompt: string, history: { role: string; parts: { text: string }[] }[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [...history, { role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
        }
      });
      return response.text;
    } catch (error) {
      console.error("Gemini Text Error:", error);
      return "I encountered an error while processing your request.";
    }
  }

  async generateImage(prompt: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: `Generate a high quality image of: ${prompt}` }]
        },
        config: {
          imageConfig: { aspectRatio: "1:1" }
        }
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (error) {
      console.error("Gemini Image Error:", error);
      return null;
    }
  }

  async processMultimodal(text: string, base64Data: string, mimeType: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType } },
            { text: text || "Please analyze this file." }
          ]
        },
        config: {
          systemInstruction: SYSTEM_INSTRUCTION
        }
      });
      return response.text;
    } catch (error) {
      console.error("Multimodal Error:", error);
      return "Error processing file.";
    }
  }

  async tts(text: string): Promise<string | null> {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              // 'Charon' or 'Fenrir' typically provide deeper, more mature male tones suitable for "Gombhir"
              prebuiltVoiceConfig: { voiceName: 'Charon' } 
            }
          }
        }
      });
      return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || null;
    } catch (error) {
      console.error("TTS Error:", error);
      return null;
    }
  }

  connectLive(callbacks: {
    onopen: () => void;
    onmessage: (message: LiveServerMessage) => void;
    onerror: (e: ErrorEvent) => void;
    onclose: (e: CloseEvent) => void;
  }) {
    return this.ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks,
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Charon' } },
        },
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });
  }
}

