  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import ChatArea from './components/ChatArea';
import InputArea from './components/InputArea';
import LiveArea from './components/LiveArea';
import Avatar from './components/Avatar';
import { ChatSession, Message } from './types';
import { gemini } from './services/geminiService';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'live'>('chat');
  const [isProcessing, setIsProcessing] = useState(false);

  const currentSession = sessions.find(s => s.id === currentSessionId);

  useEffect(() => {
    const saved = localStorage.getItem('waso_chats');
    if (saved) {
      const parsed = JSON.parse(saved);
      setSessions(parsed);
      if (parsed.length > 0) setCurrentSessionId(parsed[0].id);
    } else {
      createNewChat();
    }
  }, []);

  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('waso_chats', JSON.stringify(sessions));
    }
  }, [sessions]);

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Chat',
      messages: [],
      updatedAt: Date.now(),
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setIsSidebarOpen(false);
    setActiveTab('chat');
  };

  const handleSendMessage = async (text: string, file?: File, isImageGen = false) => {
    if (!currentSessionId || (!text && !file)) return;

    setIsProcessing(true);
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now(),
      type: file ? (file.type.startsWith('image/') ? 'image' : 'file') : 'text',
    };

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return {
          ...s,
          messages: [...s.messages, userMessage],
          title: s.messages.length === 0 ? (text.slice(0, 30) || 'Multimodal Interaction') : s.title,
          updatedAt: Date.now()
        };
      }
      return s;
    }));

    try {
      let aiResponse: string | null = '';
      let imageUrl: string | undefined;

      if (isImageGen) {
        const result = await gemini.generateImage(text);
        if (result) {
          aiResponse = "Generated image:";
          imageUrl = result;
        } else {
          aiResponse = "Sorry, I couldn't generate that image.";
        }
      } else if (file) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = e.target?.result?.toString().split(',')[1];
          if (base64) {
            const resp = await gemini.processMultimodal(text, base64, file.type);
            addAiMessage(resp || 'Failed to process file.');
          }
        };
        reader.readAsDataURL(file);
        setIsProcessing(false);
        return;
      } else {
        const history = currentSession?.messages.map(m => ({
          role: m.role === 'user' ? 'user' : 'model',
          parts: [{ text: m.content }]
        })) || [];
        aiResponse = await gemini.generateTextResponse(text, history);
      }

      if (aiResponse) addAiMessage(aiResponse, imageUrl);
    } catch (err) {
      console.error(err);
      addAiMessage("An unexpected error occurred.");
    } finally {
      setIsProcessing(false);
    }
  };

  const addAiMessage = (content: string, imageUrl?: string) => {
    const aiMessage: Message = {
      id: Date.now().toString(),
      role: 'assistant',
      content,
      imageUrl,
      timestamp: Date.now(),
      type: imageUrl ? 'image' : 'text',
    };

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, aiMessage], updatedAt: Date.now() };
      }
      return s;
    }));
  };

  const deleteSession = (id: string) => {
    setSessions(prev => prev.filter(s => s.id !== id));
    if (currentSessionId === id) setCurrentSessionId(null);
  };

  return (
    <div className="flex h-screen w-full theme-gradient text-white overflow-hidden">
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        sessions={sessions}
        currentSessionId={currentSessionId}
        onSelectSession={setCurrentSessionId}
        onNewChat={createNewChat}
        onDeleteSession={deleteSession}
      />

      <div className="flex flex-col flex-1 relative min-w-0">
        <Navbar 
          onOpenSidebar={() => setIsSidebarOpen(true)} 
          activeTab={activeTab}
          onTabChange={setActiveTab}
          onNewChat={createNewChat}
        />

        <main className="flex-1 flex flex-col items-center justify-center relative px-4 md:px-8 max-w-5xl mx-auto w-full overflow-hidden">
          {activeTab === 'chat' ? (
            <>
              {currentSession?.messages.length === 0 && !isProcessing && (
                <div className="flex flex-col items-center animate-fade-in text-center space-y-6">
                  <Avatar className="w-48 h-48 drop-shadow-[0_0_30px_rgba(0,180,216,0.3)]" />
                  <h1 className="text-4xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-cyan-300">
                    Hey, I am WASO
                  </h1>
                  <p className="text-gray-400 max-w-md text-lg">
                    I am ready to assist you with my গম্ভীর voice in Bengali and English. Wasin created me.
                  </p>
                </div>
              )}
              <ChatArea 
                messages={currentSession?.messages || []} 
                isProcessing={isProcessing}
              />
              <InputArea 
                onSendMessage={handleSendMessage} 
                isProcessing={isProcessing}
              />
            </>
          ) : (
            <LiveArea />
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { Volume2, VolumeX, Bot, User, Loader2 } from 'lucide-react';
import { Message } from '../types';
// Fixed: Imported 'decode' instead of the non-existent 'decodeBase64'.
import { gemini, decodeAudioData, decode } from '../services/geminiService';

interface ChatAreaProps {
  messages: Message[];
  isProcessing: boolean;
}

const ChatArea: React.FC<ChatAreaProps> = ({ messages, isProcessing }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const [playingId, setPlayingId] = useState<string | null>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
    }
  }, [messages, isProcessing]);

  const speak = async (message: Message) => {
    if (playingId === message.id) {
      setPlayingId(null);
      return;
    }

    try {
      setPlayingId(message.id);
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const base64Audio = await gemini.tts(message.content);
      if (base64Audio) {
        // Fixed: Use the manually implemented 'decode' function.
        const audioBuffer = await decodeAudioData(
          decode(base64Audio),
          audioContextRef.current,
          24000,
          1
        );
        const source = audioContextRef.current.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => setPlayingId(null);
        source.start();
      } else {
        setPlayingId(null);
      }
    } catch (err) {
      console.error(err);
      setPlayingId(null);
    }
  };

  return (
    <div 
      ref={scrollRef}
      className="w-full flex-1 overflow-y-auto custom-scrollbar space-y-6 pt-4 pb-32"
    >
      {messages.map((msg) => (
        <div 
          key={msg.id} 
          className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
        >
          <div className={`flex max-w-[85%] md:max-w-[75%] space-x-3 ${msg.role === 'user' ? 'flex-row-reverse space-x-reverse' : 'flex-row'}`}>
            <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${msg.role === 'user' ? 'bg-[#00b4d8]/20' : 'bg-white/10'}`}>
              {msg.role === 'user' ? <User size={18} className="text-[#00b4d8]" /> : <Bot size={18} className="text-blue-400" />}
            </div>

            <div className="flex flex-col space-y-2">
              <div className={`p-4 rounded-2xl relative group ${
                msg.role === 'user' 
                ? 'bg-blue-600/20 border border-blue-500/20 text-blue-50 rounded-tr-none' 
                : 'bg-white/5 border border-white/5 text-gray-200 rounded-tl-none'
              }`}>
                {msg.imageUrl && (
                  <img 
                    src={msg.imageUrl} 
                    alt="AI Generated" 
                    className="w-full max-w-sm rounded-lg mb-3 shadow-lg border border-white/10" 
                  />
                )}

                <div className="whitespace-pre-wrap leading-relaxed text-[15px]">
                  {msg.content}
                </div>

                {msg.role === 'assistant' && msg.content && (
                  <button 
                    onClick={() => speak(msg)}
                    className="absolute -bottom-10 left-0 p-2 text-gray-500 hover:text-[#00b4d8] transition-colors"
                  >
                    {playingId === msg.id ? <VolumeX size={18} className="animate-pulse" /> : <Volume2 size={18} />}
                  </button>
                )}
              </div>
            </div>
          </div>
        </div>
      ))}

      {isProcessing && (
        <div className="flex justify-start items-center space-x-3 text-gray-500">
          <div className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center">
            <Loader2 size={18} className="animate-spin" />
          </div>
          <span className="text-sm font-medium animate-pulse">WASO is thinking...</span>
        </div>
      )}
    </div>
  );
};

