  const startEditing = (msg: Message) => {
    setEditingId(msg.id);
    setEditValue(msg.content);
  };

  const cancelEditing = () => {
    setEditingId(null);
    setEditValue('');
  };

  const submitEdit = (id: string) => {
    if (onEditMessage && editValue.trim()) {
      onEditMessage(id, editValue);
