  isProcessing: boolean;
}

const InputArea: React.FC<InputAreaProps> = ({ onSendMessage, isProcessing }) => {
  const [input, setInput] = useState('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [isImageGenMode, setIsImageGenMode] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setInput(prev => prev + ' ' + transcript);
        setIsListening(false);
      };

      recognitionRef.current.onerror = () => setIsListening(false);
      recognitionRef.current.onend = () => setIsListening(false);
    }
  }, []);

  const handleSend = () => {
    if ((!input.trim() && !selectedFile) || isProcessing) return;
    onSendMessage(input, selectedFile || undefined, isImageGenMode);
    setInput('');
    setSelectedFile(null);
    setIsImageGenMode(false);
  };

  const toggleListen = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      try {
        recognitionRef.current?.start();
        setIsListening(true);
      } catch (e) {
        console.error("Speech recognition already started");
      }
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedFile(e.target.files[0]);
    }
  };

  return (
    <div className="w-full flex flex-col items-center py-4 md:py-6 px-2 md:px-0 relative z-20">
      <div className="w-full max-w-3xl">
        {selectedFile && (
          <div className="mb-2 ml-2 flex items-center space-x-2 bg-blue-500/30 text-white px-3 py-1 rounded-full w-fit border border-blue-500/30 shadow-lg animate-fade-in">
            <span className="text-[10px] md:text-xs truncate max-w-[150px] md:max-w-[200px]">{selectedFile.name}</span>
            <button onClick={() => setSelectedFile(null)} className="hover:text-red-400 transition-colors">
              <X size={12} />
            </button>
          </div>
        )}

        <div className="relative input-glass rounded-[24px] md:rounded-[28px] shadow-2xl overflow-hidden border border-white/10 group focus-within:border-[#00b4d8]/40 transition-all duration-300">
          <div className="flex items-end p-1.5 md:p-2">
            <div className="flex items-center space-x-0.5 md:space-x-1 pl-1 pb-1">
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="p-2 text-gray-400 hover:text-[#00b4d8] rounded-full transition-all hover:bg-white/5"
                title="Upload file"
              >
                <FileUp size={20} />
              </button>
              <button 
                onClick={() => setIsImageGenMode(!isImageGenMode)}
                className={`p-2 rounded-full transition-all ${isImageGenMode ? 'text-purple-400 bg-purple-500/10' : 'text-gray-400 hover:text-purple-400 hover:bg-white/5'}`}
                title="Toggle Image Mode"
              >
                <Sparkles size={20} />
              </button>
            </div>

            <textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.shiftKey && window.innerWidth > 768) {
                  e.preventDefault();
                  handleSend();
                }
              }}
              placeholder={isImageGenMode ? "Describe the image..." : "Ask WASO..."}
              className="flex-1 bg-transparent border-none outline-none resize-none py-2 px-2 md:px-3 text-white placeholder-gray-500 max-h-32 text-sm md:text-base leading-snug custom-scrollbar"
              rows={1}
            />

            <div className="flex items-center space-x-1 pr-1 pb-1">
              <button 
                onClick={toggleListen}
                className={`p-2 rounded-full transition-all ${isListening ? 'text-red-400 bg-red-500/10 animate-pulse' : 'text-gray-400 hover:text-[#00b4d8] hover:bg-white/5'}`}
              >
                <Mic size={20} />
              </button>

              <button 
                onClick={handleSend}
                disabled={(!input.trim() && !selectedFile) || isProcessing}
                className={`p-2 rounded-full transition-all ${
                  (!input.trim() && !selectedFile) || isProcessing
