              >
                <ArrowUp size={20} />
              </button>
            </div>
          </div>
        </div>

        <input 
          type="file" 
          ref={fileInputRef} 
          onChange={handleFileChange} 
          className="hidden" 
          accept="image/*,.pdf,.pptx"
        />

        <p className="text-[9px] text-center text-gray-600 mt-2 uppercase tracking-[0.2em] font-medium">
          WASO AI • POWERED BY WASIN
        </p>
      </div>
    </div>
  );
};

