const ChatArea: React.FC<ChatAreaProps> = ({ messages, isProcessing, onEditMessage }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isProcessing]);

  const speak = async (message: Message) => {
    if (playingId === message.id) {
      setPlayingId(null);
      return;
    }

    try {
      setPlayingId(message.id);
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const base64Audio = await gemini.tts(message.content);
      if (base64Audio) {
        const audioBuffer = await decodeAudioData(
          decode(base64Audio),
          audioContextRef.current,
          24000,
          1
        );
        const source = audioContextRef.current.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => setPlayingId(null);
        source.start();
      } else {
        setPlayingId(null);
      }
    } catch (err) {
      console.error(err);
      setPlayingId(null);
    }
  };

  const startEditing = (msg: Message) => {
    setEditingId(msg.id);
    setEditValue(msg.content);
  };

  const cancelEditing = () => {
    setEditingId(null);
    setEditValue('');
  };

  const submitEdit = (id: string) => {
    if (onEditMessage && editValue.trim()) {
      onEditMessage(id, editValue);
    }
    setEditingId(null);
    setEditValue('');
  };

  return (
    <div 
      ref={scrollRef}
      className="flex-1 overflow-y-auto custom-scrollbar space-y-4 md:space-y-6 pt-4 pb-12 px-1 scroll-smooth"
    >
      {messages.map((msg) => (
        <div 
          key={msg.id} 
          className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
        >
          <div className={`flex max-w-[92%] md:max-w-[85%] space-x-2 md:space-x-4 ${msg.role === 'user' ? 'flex-row-reverse space-x-reverse' : 'flex-row'}`}>
            <div className={`flex-shrink-0 w-8 h-8 md:w-9 md:h-9 rounded-full flex items-center justify-center transition-all ${msg.role === 'user' ? 'bg-[#00b4d8]/20 ring-1 ring-[#00b4d8]/30' : 'bg-white/10 ring-1 ring-white/20 shadow-lg'}`}>
              {msg.role === 'user' ? <User size={18} className="text-[#00b4d8]" /> : <Bot size={18} className="text-blue-400" />}
            </div>

            <div className="flex flex-col space-y-1 w-full min-w-0">
              <div className={`p-4 md:p-5 rounded-2xl relative group transition-all duration-300 shadow-xl ${
                msg.role === 'user' 
                ? 'bg-blue-600/10 border border-blue-500/20 text-blue-50 rounded-tr-none' 
                : 'bg-[#0a192f]/40 backdrop-blur-md border border-white/5 text-gray-200 rounded-tl-none'
              }`}>
                {msg.imageUrl && (
                  <img 
                    src={msg.imageUrl} 
                    alt="AI Generated" 
                    className="w-full max-w-lg rounded-xl mb-4 shadow-2xl border border-white/10 animate-fade-in" 
                  />
                )}

                {editingId === msg.id ? (
                  <div className="flex flex-col space-y-3 min-w-[250px] md:min-w-[400px]">
                    <textarea 
                      className="bg-black/40 border border-[#00b4d8]/30 rounded-xl p-3 text-sm text-white focus:outline-none focus:ring-1 focus:ring-[#00b4d8] min-h-[120px] transition-all"
                      value={editValue}
                      onChange={(e) => setEditValue(e.target.value)}
                      autoFocus
                    />
                    <div className="flex justify-end space-x-3">
                      <button onClick={cancelEditing} className="p-2 text-gray-400 hover:text-red-400 transition-colors">
                        <CloseIcon size={18} />
                      </button>
                      <button onClick={() => submitEdit(msg.id)} className="p-2 text-[#00b4d8] hover:text-[#00d8ff] transition-colors">
                        <Check size={18} />
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="markdown-content">
                    <ReactMarkdown 
                      remarkPlugins={[remarkGfm]}
                      components={{
                        code({ node, inline, className, children, ...props }: any) {
                          const match = /language-(\w+)/.exec(className || '');
                          const value = String(children).replace(/\n$/, '');
                          return !inline ? (
                            <CodeBlock language={match ? match[1] : ''} value={value} />
                          ) : (
                            <code className="bg-black/30 text-blue-300 px-1.5 py-0.5 rounded text-[13px] font-mono border border-white/5" {...props}>
                              {children}
                            </code>
                          );
                        },
                        h1: ({ children }) => <h1 className="text-2xl font-black mb-4 mt-6 text-[#00b4d8] border-b border-white/10 pb-2">{children}</h1>,
                        h2: ({ children }) => <h2 className="text-xl font-bold mb-3 mt-5 flex items-center"><span className="w-2 h-2 bg-[#00b4d8] mr-2 transform rotate-45"></span>{children}</h2>,
                        p: ({ children }) => <p className="mb-4 last:mb-0 leading-relaxed text-[15px] opacity-90">{children}</p>,
                        ul: ({ children }) => <ul className="list-none space-y-2 mb-4 ml-2">{children}</ul>,
                        li: ({ children }) => <li className="flex items-start"><span className="text-[#00b4d8] mr-2 mt-1.5 scale-75">◆</span><span>{children}</span></li>,
