const ChatArea: React.FC<ChatAreaProps> = ({ messages, isProcessing, onEditMessage }) => {
  const scrollRef = useRef<HTMLDivElement>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isProcessing]);

  const speak = async (message: Message) => {
    if (playingId === message.id) {
      setPlayingId(null);
      return;
    }

    try {
      setPlayingId(message.id);
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      }

      const base64Audio = await gemini.tts(message.content);
      if (base64Audio) {
        const audioBuffer = await decodeAudioData(
          decode(base64Audio),
          audioContextRef.current,
          24000,
          1
        );
        const source = audioContextRef.current.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContextRef.current.destination);
        source.onended = () => setPlayingId(null);
        source.start();
      } else {
        setPlayingId(null);
      }
    } catch (err) {
      console.error(err);
      setPlayingId(null);
    }
  };

  const startEditing = (msg: Message) => {
    setEditingId(msg.id);
    setEditValue(msg.content);
  };

  const cancelEditing = () => {
    setEditingId(null);
    setEditValue('');
  };

  const submitEdit = (id: string) => {
    if (onEditMessage && editValue.trim()) {
      onEditMessage(id, editValue);
    }
    setEditingId(null);
    setEditValue('');
  };

  return (
    <div 
      ref={scrollRef}
      className="flex-1 overflow-y-auto custom-scrollbar space-y-4 md:space-y-6 pt-4 pb-12 px-1 scroll-smooth"
    >
      {messages.map((msg) => (
        <div 
          key={msg.id} 
          className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
        >
          <div className={`flex max-w-[98%] space-x-2 md:space-x-4 ${msg.role === 'user' ? 'flex-row-reverse space-x-reverse' : 'flex-row'}`}>
            <div className={`flex-shrink-0 w-8 h-8 md:w-9 md:h-9 rounded-full flex items-center justify-center transition-all ${msg.role === 'user' ? 'bg-[#00b4d8]/20 ring-1 ring-[#00b4d8]/30' : 'bg-white/10 ring-1 ring-white/20 shadow-lg'}`}>
              {msg.role === 'user' ? <User size={18} className="text-[#00b4d8]" /> : <Bot size={18} className="text-blue-400" />}
            </div>

            <div className="flex flex-col space-y-1 w-full min-w-0">
              <div className={`p-4 md:p-5 rounded-2xl relative group transition-all duration-300 shadow-xl ${
                msg.role === 'user' 
                ? 'bg-blue-600/10 border border-blue-500/20 text-blue-50 rounded-tr-none' 
                : 'bg-[#0a192f]/40 backdrop-blur-md border border-white/5 text-gray-200 rounded-tl-none'
              }`}>
                {msg.imageUrl && (
                  <img 
                    src={msg.imageUrl} 
                    alt="AI Generated" 
                    className="w-full max-w-lg rounded-xl mb-4 shadow-2xl border border-white/10 animate-fade-in" 
                  />
                )}

                {editingId === msg.id ? (
                  <div className="flex flex-col space-y-3 min-w-[250px] md:min-w-[400px]">
                    <textarea 
                      className="bg-black/40 border border-[#00b4d8]/30 rounded-xl p-3 text-sm text-white focus:outline-none focus:ring-1 focus:ring-[#00b4d8] min-h-[120px] transition-all"
                      value={editValue}
                      onChange={(e) => setEditValue(e.target.value)}
                      autoFocus
                    />
                    <div className="flex justify-end space-x-3">
                      <button onClick={cancelEditing} className="p-2 text-gray-400 hover:text-red-400 transition-colors">
                        <CloseIcon size={18} />
                      </button>
                      <button onClick={() => submitEdit(msg.id)} className="p-2 text-[#00b4d8] hover:text-[#00d8ff] transition-colors">
                        <Check size={18} />
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="markdown-content">
                    <ReactMarkdown 
                      remarkPlugins={[remarkGfm]}
                      components={{
                        code({ node, inline, className, children, ...props }: any) {
                          const match = /language-(\w+)/.exec(className || '');
                          const value = String(children).replace(/\n$/, '');
                          return !inline ? (
                            <CodeBlock language={match ? match[1] : ''} value={value} />
                          ) : (
                            <code className="bg-black/30 text-blue-300 px-1.5 py-0.5 rounded text-[13px] font-mono border border-white/5" {...props}>
                              {children}
                            </code>
                          );
                        },
                        h1: ({ children }) => <h1 className="text-2xl font-black mb-4 mt-6 text-[#00b4d8] border-b border-white/10 pb-2">{children}</h1>,
                        h2: ({ children }) => <h2 className="text-xl font-bold mb-3 mt-5 flex items-center"><span className="w-2 h-2 bg-[#00b4d8] mr-2 transform rotate-45"></span>{children}</h2>,
                        p: ({ children }) => <p className="mb-4 last:mb-0 leading-relaxed text-[15px] opacity-90">{children}</p>,
                        ul: ({ children }) => <ul className="list-none space-y-2 mb-4 ml-2">{children}</ul>,
                        li: ({ children }) => <li className="flex items-start"><span className="text-[#00b4d8] mr-2 mt-1.5 scale-75">◆</span><span>{children}</span></li>,
                        strong: ({ children }) => <strong className="text-white font-bold">{children}</strong>,
                      }}
                    >
                      {msg.content}
                    </ReactMarkdown>

                    {msg.role === 'user' && !isProcessing && (
                      <button 
                        onClick={() => startEditing(msg)}
                        className="absolute -right-10 md:-right-12 top-0 opacity-0 group-hover:opacity-100 p-2 text-gray-500 hover:text-[#00b4d8] transition-all hover:bg-white/5 rounded-xl"
                      >
                        <Edit2 size={16} />
                      </button>
                    )}

                    {msg.role === 'assistant' && msg.content && (
                      <div className="flex items-center space-x-3 mt-4 pt-3 border-t border-white/5">
                        <button 
                          onClick={() => speak(msg)}
                          className={`flex items-center space-x-2 px-3 py-1.5 rounded-full text-[11px] font-black tracking-tighter uppercase transition-all ${
                            playingId === msg.id 
                            ? 'bg-[#00b4d8] text-black shadow-[0_0_15px_rgba(0,180,216,0.4)]' 
                            : 'bg-white/5 text-gray-400 hover:text-white hover:bg-white/10'
                          }`}
                        >
                          {playingId === msg.id ? <VolumeX size={14} className="animate-pulse" /> : <Volume2 size={14} />}
                          <span>{playingId === msg.id ? 'Stop Audio' : 'Play Audio'}</span>
                        </button>
                      </div>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      ))}

      {isProcessing && (
        <div className="flex justify-start items-center space-x-4 ml-2 py-4 animate-fade-in">
          <div className="relative">
            <div className="w-9 h-9 rounded-full bg-[#0a192f] flex items-center justify-center ring-1 ring-blue-500/30">
              <Loader2 size={16} className="text-blue-400 animate-spin" />
            </div>
            <div className="absolute -top-1 -right-1 w-3 h-3 bg-blue-500 rounded-full animate-ping opacity-20"></div>
          </div>
          <div className="flex flex-col">
            <span className="text-xs font-black text-[#00b4d8] uppercase tracking-widest">Waso Analyzer</span>
            <span className="text-[10px] text-gray-500 font-medium">Processing request with deep thinking...</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default ChatArea;

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import ChatArea from './components/ChatArea';
import InputArea from './components/InputArea';
import LiveArea from './components/LiveArea';
import Avatar from './components/Avatar';
import { ChatSession, Message } from './types';
import { gemini } from './services/geminiService';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'live'>('chat');
  const [isProcessing, setIsProcessing] = useState(false);

  const currentSession = sessions.find(s => s.id === currentSessionId);

  useEffect(() => {
    const saved = localStorage.getItem('waso_chats');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setSessions(parsed);
        if (parsed.length > 0) setCurrentSessionId(parsed[0].id);
      } catch (e) {
        createNewChat();
      }
    } else {
      createNewChat();
    }
  }, []);

  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('waso_chats', JSON.stringify(sessions));
    }
  }, [sessions]);

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Chat',
      messages: [],
      updatedAt: Date.now(),
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setIsSidebarOpen(false);
    setActiveTab('chat');
  };

  const handleSendMessage = async (text: string, file?: File, isImageGen = false) => {
    if (!currentSessionId || (!text && !file)) return;

    setIsProcessing(true);
    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now(),
      type: file ? (file.type.startsWith('image/') ? 'image' : 'file') : 'text',
    };

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return {
          ...s,
          messages: [...s.messages, userMessage],
          title: s.messages.length === 0 ? (text.slice(0, 30) || 'Multimodal Interaction') : s.title,
          updatedAt: Date.now()
        };
      }
      return s;
    }));

    try {
      let aiResponse: string | null = '';
      let imageUrl: string | undefined;

      if (isImageGen) {
        const result = await gemini.generateImage(text);
        if (result) {
          aiResponse = "Generated image:";
          imageUrl = result;
        } else {
          aiResponse = "Sorry, I couldn't generate that image.";
        }
      } else if (file) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = e.target?.result?.toString().split(',')[1];
          if (base64) {
            const resp = await gemini.processMultimodal(text, base64, file.type);
            addAiMessage(resp || 'Failed to process file.');
          }
        };
        reader.readAsDataURL(file);
        return;
      } else {
        const history = currentSession?.messages.map(m => ({
          role: m.role === 'user' ? 'user' : 'model',
          parts: [{ text: m.content }]
        })) || [];
        aiResponse = await gemini.generateTextResponse(text, history);
      }

      if (aiResponse) addAiMessage(aiResponse, imageUrl);
    } catch (err) {
      console.error(err);
      addAiMessage("An unexpected error occurred.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleEditMessage = async (messageId: string, newText: string) => {
    if (!currentSessionId || !newText.trim() || isProcessing) return;

    setIsProcessing(true);

    // Find session and slice messages up to the one being edited
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        const msgIndex = s.messages.findIndex(m => m.id === messageId);
        if (msgIndex === -1) return s;

        // Remove everything after this message and replace this message with new text
        const newMessages = s.messages.slice(0, msgIndex);
        return {
          ...s,
          messages: newMessages,
          updatedAt: Date.now()
        };
      }
      return s;
    }));

    // Now send the new message as if it was fresh
    await handleSendMessage(newText);
  };

  const addAiMessage = (content: string, imageUrl?: string) => {
    const aiMessage: Message = {
      id: Date.now().toString(),
      role: 'assistant',
      content,
      imageUrl,
      timestamp: Date.now(),
      type: imageUrl ? 'image' : 'text',
    };

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, aiMessage], updatedAt: Date.now() };
      }
      return s;
    }));
  };

  const deleteSession = (id: string) => {
    setSessions(prev => prev.filter(s => s.id !== id));
    if (currentSessionId === id) {
      const remaining = sessions.filter(s => s.id !== id);
      if (remaining.length > 0) setCurrentSessionId(remaining[0].id);
      else createNewChat();
    }
  };

  return (
    <div className="flex flex-col h-screen w-full theme-gradient text-white overflow-hidden" style={{ height: 'var(--dvh)' }}>
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        sessions={sessions}
        currentSessionId={currentSessionId}
        onSelectSession={setCurrentSessionId}
        onNewChat={createNewChat}
        onDeleteSession={deleteSession}
      />

      <Navbar 
        onOpenSidebar={() => setIsSidebarOpen(true)} 
        activeTab={activeTab}
        onTabChange={setActiveTab}
        onNewChat={createNewChat}
      />

      <div className="flex-1 relative flex flex-col min-w-0 w-full overflow-hidden">
        <main className="flex-1 flex flex-col relative w-full h-full overflow-hidden">
          {activeTab === 'chat' ? (
            <div className="flex-1 flex flex-col w-full mx-auto px-1 md:px-4 relative overflow-hidden">
              {currentSession?.messages.length === 0 && !isProcessing && (
                <div className="absolute inset-0 flex flex-col items-center justify-center animate-fade-in text-center space-y-4 md:space-y-6 px-4 z-0 pointer-events-none">
                  <Avatar className="w-32 h-32 md:w-48 md:h-48 drop-shadow-[0_0_30px_rgba(0,180,216,0.3)] pointer-events-auto" />
                  <div className="pointer-events-auto">
                    <h1 className="text-3xl md:text-4xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-cyan-300">
                      Hey, I am WASO
                    </h1>
                    <p className="text-gray-400 max-w-sm md:text-lg mt-2">
                      I am ready to assist you in Bengali and English. Wasin created me.
                    </p>
                  </div>
                </div>
              )}

              <div className="flex-1 overflow-hidden relative flex flex-col w-full">
                <ChatArea 
                  messages={currentSession?.messages || []} 
                  isProcessing={isProcessing}
                  onEditMessage={handleEditMessage}
                />
              </div>

              <div className="shrink-0 w-full max-w-4xl mx-auto">
                <InputArea 
                  onSendMessage={handleSendMessage} 
                  isProcessing={isProcessing}
                />
              </div>
            </div>
          ) : (
            <div className="flex-1 w-full max-w-4xl mx-auto px-4 h-full flex flex-col overflow-hidden">
              <LiveArea />
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { Volume2, VolumeX, Bot, User, Loader2, Edit2, Check, X as CloseIcon, Copy, ClipboardCheck, Download } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { Message } from '../types';
import { gemini, decodeAudioData, decode } from '../services/geminiService';

interface ChatAreaProps {
  messages: Message[];
  isProcessing: boolean;
  onEditMessage?: (id: string, newText: string) => void;
}

const CopyButton = ({ text, className = "" }: { text: string; className?: string }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <button 
      onClick={handleCopy}
      className={`flex items-center space-x-1 px-2 py-1 rounded-md transition-all ${
        copied ? 'text-green-400 bg-green-500/10' : 'text-gray-400 hover:text-white hover:bg-white/5'
      } ${className}`}
      title="Copy text"
    >
      {copied ? <ClipboardCheck size={14} /> : <Copy size={14} />}
      <span className="text-[10px] font-bold uppercase tracking-tighter">{copied ? 'Copied' : 'Copy'}</span>
    </button>
  );
};

const CodeBlock = ({ language, value }: { language: string; value: string }) => {
  const [copied, setCopied] = useState(false);

  const copyToClipboard = () => {
    navigator.clipboard.writeText(value);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="my-6 rounded-xl overflow-hidden border border-white/10 shadow-2xl transition-all duration-300">
      {/* Code Header */}
      <div className="pro-code-header flex items-center justify-between px-4 py-2.5 select-none bg-[#1a1a1a]">
        <span className="text-[11px] font-bold uppercase tracking-widest text-gray-400 font-mono">{language || 'code'}</span>
        <button 
          onClick={copyToClipboard}
          className="flex items-center space-x-1.5 text-[11px] font-medium text-gray-400 hover:text-white transition-colors"
        >
          {copied ? <ClipboardCheck size={14} className="text-green-400" /> : <Copy size={14} />}
          <span>{copied ? 'Copied' : 'Copy code'}</span>
        </button>
      </div>

      {/* Solid Black Background for the entire block */}
      <div className="bg-[#000000] p-0 m-0">
        <SyntaxHighlighter
          language={language || 'text'}
          style={vscDarkPlus}
          customStyle={{
            margin: 0,
            padding: '1.5rem',
            fontSize: '14px',
            backgroundColor: '#000000', // Cohesive black background
            lineHeight: '1.6',
            border: 'none',
          }}
          codeTagProps={{
            style: {
              fontFamily: '"JetBrains Mono", monospace',
              backgroundColor: 'transparent', // Disable per-line background
              display: 'block', // Ensure it flows as one block
            },
          }}
        >
          {value}
        </SyntaxHighlighter>
      </div>
    </div>
  );
};

const ChatArea: React.FC<ChatAreaProps> = ({ messages, isProcessing, onEditMessage }) => {
