  return (
    <div 
      ref={scrollRef}
      className="flex-1 overflow-y-auto custom-scrollbar space-y-4 md:space-y-6 pt-4 pb-12 px-1 md:px-2 scroll-smooth w-full"
    >
      {messages.map((msg) => (
        <div 
          key={msg.id} 
          className={`flex w-full ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
