          <div className={`flex w-full md:max-w-[98%] space-x-1.5 md:space-x-4 ${msg.role === 'user' ? 'flex-row-reverse space-x-reverse pl-4' : 'flex-row pr-4'}`}>
            <div className={`flex-shrink-0 w-7 h-7 md:w-9 md:h-9 rounded-full flex items-center justify-center transition-all mt-1 ${msg.role === 'user' ? 'bg-[#00b4d8]/20 ring-1 ring-[#00b4d8]/30' : 'bg-white/10 ring-1 ring-white/20 shadow-lg'}`}>
