                {msg.imageUrl && (
                  <div className="relative group/img mb-4 max-w-2xl">
                    <img 
                      src={msg.imageUrl} 
                      alt="AI Generated" 
                      className="w-full rounded-xl shadow-2xl border border-white/10 animate-fade-in" 
