                    <button 
                      onClick={() => downloadImage(msg.imageUrl!)}
                      className="absolute top-3 right-3 p-2.5 bg-black/60 backdrop-blur-md text-white rounded-full opacity-0 group-hover/img:opacity-100 transition-all hover:bg-[#00b4d8] active:scale-95 shadow-lg"
                      title="Download Image"
                    >
                      <Download size={18} />
