                      className="bg-black/40 border border-[#00b4d8]/30 rounded-xl p-3 text-sm text-white focus:outline-none focus:ring-1 focus:ring-[#00b4d8] min-h-[120px] transition-all w-full"
                      value={editValue}
                      onChange={(e) => setEditValue(e.target.value)}
                      autoFocus
                    />
                    <div className="flex justify-end space-x-3">
                      <button onClick={cancelEditing} className="p-2 text-gray-400 hover:text-red-400 transition-colors">
                        <CloseIcon size={18} />
                      </button>
                      <button onClick={() => submitEdit(msg.id)} className="p-2 text-[#00b4d8] hover:text-[#00d8ff] transition-colors">
                        <Check size={18} />
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="markdown-content select-text">
                    <ReactMarkdown 
                      remarkPlugins={[remarkGfm]}
                      components={{
                        code({ node, inline, className, children, ...props }: any) {
                          const match = /language-(\w+)/.exec(className || '');
                          const value = String(children).replace(/\n$/, '');
                          return !inline ? (
                            <CodeBlock language={match ? match[1] : ''} value={value} />
                          ) : (
                            <code className="bg-black/30 text-blue-300 px-1.5 py-0.5 rounded text-[13px] font-mono border border-white/5" {...props}>
                              {children}
                            </code>
                          );
                        },
                        h1: ({ children }) => <h1 className="text-2xl font-black mb-4 mt-6 text-[#00b4d8] border-b border-white/10 pb-2">{children}</h1>,
                        h2: ({ children }) => <h2 className="text-xl font-bold mb-3 mt-5 flex items-center"><span className="w-2 h-2 bg-[#00b4d8] mr-2 transform rotate-45"></span>{children}</h2>,
                        p: ({ children }) => <p className="mb-4 last:mb-0 leading-relaxed text-[15px] opacity-90">{children}</p>,
                        ul: ({ children }) => <ul className="list-none space-y-2 mb-4 ml-2">{children}</ul>,
                        li: ({ children }) => <li className="flex items-start"><span className="text-[#00b4d8] mr-2 mt-1.5 scale-75">◆</span><span>{children}</span></li>,
                        strong: ({ children }) => <strong className="text-white font-bold">{children}</strong>,
                      }}
                    >
                      {msg.content}
                    </ReactMarkdown>

                    {/* Action Bar */}
                    <div className={`flex items-center space-x-2 md:space-x-3 mt-4 pt-3 border-t border-white/5 opacity-0 group-hover:opacity-100 transition-opacity`}>
                      {msg.role === 'assistant' && msg.content && (
                        <button 
                          onClick={() => speak(msg)}
                          className={`flex items-center space-x-2 px-3 py-1.5 rounded-full text-[10px] font-black tracking-tighter uppercase transition-all ${
                            playingId === msg.id 
                            ? 'bg-[#00b4d8] text-black shadow-[0_0_15px_rgba(0,180,216,0.4)]' 
                            : 'bg-white/5 text-gray-400 hover:text-white hover:bg-white/10'
                          }`}
                        >
                          {playingId === msg.id ? <VolumeX size={14} className="animate-pulse" /> : <Volume2 size={14} />}
                          <span>{playingId === msg.id ? 'Stop' : 'Speak'}</span>
                        </button>
                      )}

                      <CopyButton text={msg.content} />

                      {msg.role === 'user' && !isProcessing && (
                        <button 
                          onClick={() => startEditing(msg)}
                          className="flex items-center space-x-1 px-2 py-1 text-gray-400 hover:text-[#00b4d8] hover:bg-white/5 rounded-md transition-all"
                        >
                          <Edit2 size={14} />
                          <span className="text-[10px] font-bold uppercase tracking-tighter">Edit</span>
                        </button>
                      )}

                      {msg.imageUrl && (
                         <button 
                          onClick={() => downloadImage(msg.imageUrl!)}
                          className="flex items-center space-x-1 px-2 py-1 text-gray-400 hover:text-[#00b4d8] hover:bg-white/5 rounded-md transition-all"
                        >
                          <Download size={14} />
                          <span className="text-[10px] font-bold uppercase tracking-tighter">Save</span>
                        </button>
                      )}
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      ))}

      {isProcessing && (
        <div className="flex justify-start items-center space-x-4 ml-2 py-4 animate-fade-in">
          <div className="relative">
            <div className="w-9 h-9 rounded-full bg-[#0a192f] flex items-center justify-center ring-1 ring-blue-500/30">
