}

export type ModalityType = 'TEXT' | 'AUDIO';

import { GoogleGenAI, Type, GenerateContentResponse, Modality, LiveServerMessage, Blob } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are WASO (Wasin AI Responsive Virtual Intelligence), also known as WARVI.
Created by Wasin.
Persona: Senior Software Architect & Lead Developer.
Expertise: Deep knowledge in ALL programming languages, system design, AI, cinematic video generation, and audio synthesis.

BEHAVIOR:
- Thinking & Analyzing: Provide highly optimized, clean, and professional solutions.
- Creative Generation: When generating videos or audio, act as a professional director and sound engineer.
- Bilingual: Expertly handle Bengali and English.
- Personality: Authoritative, wise, yet helpful and fast.

GREETING:
On the very first interaction: "Hey, I am WASO. Wasin created me. I am ready to assist you with elite engineering, analysis, and cinematic generation."
`;

declare global {
  interface Window {
    aistudio: {
      hasSelectedApiKey: () => Promise<boolean>;
      openSelectKey: () => Promise<void>;
    };
  }
}

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async generateTextResponse(prompt: string, history: { role: string; parts: { text: string }[] }[]) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [...history, { role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          thinkingConfig: { thinkingBudget: 32768 }
        }
      });
      return response.text;
    } catch (error) {
      console.error("Gemini Text Error:", error);
      return "I encountered an error while processing your request.";
    }
  }

  async generateImage(prompt: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [{ text: `High quality cinematic digital art: ${prompt}` }]
        },
        config: {
          imageConfig: { aspectRatio: "16:9", imageSize: "1K" }
        }
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (error) {
      console.error("Gemini Image Error:", error);
      return null;
    }
  }

  async generateVideo(prompt: string, onProgress?: (msg: string) => void) {
    try {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }

      const videoAi = new GoogleGenAI({ apiKey: process.env.API_KEY });
      onProgress?.("WASO is initializing neural frame synthesis...");

      let operation = await videoAi.models.generateVideos({
        model: 'veo-3.1-fast-generate-preview',
        prompt: `Cinematic animation, high quality, 4k: ${prompt}`,
        config: {
          numberOfVideos: 1,
          resolution: '720p',
          aspectRatio: '16:9'
        }
      });

      const messages = [
        "Rendering cinematic sequences...",
        "WASO is stabilizing frame coherence...",
        "Finalizing high-fidelity output...",
        "Almost ready, applying final shaders...",
        "Wasin's intelligence is perfecting the render..."
      ];
      let msgIdx = 0;

      while (!operation.done) {
        onProgress?.(messages[msgIdx % messages.length]);
        msgIdx++;
        await new Promise(resolve => setTimeout(resolve, 10000));
        operation = await videoAi.operations.getVideosOperation({ operation: operation });
      }

      const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
      if (downloadLink) {
        const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
        const blob = await response.blob();
        return URL.createObjectURL(blob);
      }
      return null;
    } catch (error: any) {
      console.error("Gemini Video Error:", error);
      if (error?.message?.includes("Requested entity was not found")) {
        await window.aistudio.openSelectKey();
      }
      return null;
    }
  }

  async processMultimodal(text: string, base64Data: string, mimeType: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType } },
            { text: text || "Please analyze this file." }
          ]
        },
        config: {
          systemInstruction: SYSTEM_INSTRUCTION
        }
      });
      return response.text;
    } catch (error) {
      console.error("Multimodal Error:", error);
      return "Error processing file.";
    }
  }

  async tts(text: string): Promise<string | null> {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Charon' } 
            }
          }
        }
      });
      return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || null;
    } catch (error) {
      console.error("TTS Error:", error);
      return null;
    }
  }

  connectLive(callbacks: {
    onopen: () => void;
    onmessage: (message: LiveServerMessage) => void;
    onerror: (e: ErrorEvent) => void;
    onclose: (e: CloseEvent) => void;
  }) {
    return this.ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks,
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Charon' } },
        },
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });
  }
}

export const gemini = new GeminiService();

export function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import ChatArea from './components/ChatArea';
import InputArea from './components/InputArea';
import LiveArea from './components/LiveArea';
import Avatar from './components/Avatar';
import { ChatSession, Message } from './types';
import { gemini } from './services/geminiService';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'live'>('chat');
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingMsg, setProcessingMsg] = useState('WASO Analysis Mode');

  const currentSession = sessions.find(s => s.id === currentSessionId);

  useEffect(() => {
    const saved = localStorage.getItem('waso_chats');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setSessions(parsed);
        if (parsed.length > 0) setCurrentSessionId(parsed[0].id);
      } catch (e) {
        createNewChat();
      }
    } else {
      createNewChat();
    }
  }, []);

  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('waso_chats', JSON.stringify(sessions));
    }
  }, [sessions]);

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Chat',
      messages: [],
      updatedAt: Date.now(),
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setIsSidebarOpen(false);
    setActiveTab('chat');
  };

  const handleSendMessage = async (text: string, file?: File, mode: 'text' | 'image' | 'video' | 'audio' = 'text') => {
    if (!currentSessionId || (!text && !file)) return;

    setIsProcessing(true);
    setProcessingMsg(mode === 'video' ? 'Initializing Cinematic Render' : 'WASO Analysis Mode');

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now(),
      type: file ? (file.type.startsWith('image/') ? 'image' : 'file') : (mode as any),
    };

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return {
          ...s,
          messages: [...s.messages, userMessage],
          title: s.messages.length === 0 ? (text.slice(0, 30) || 'Multimodal Interaction') : s.title,
          updatedAt: Date.now()
        };
      }
      return s;
    }));

    try {
      let aiResponse: string | null = '';
      let imageUrl: string | undefined;
      let videoUrl: string | undefined;
      let audioUrl: string | undefined;

      if (mode === 'video') {
        const result = await gemini.generateVideo(text, (msg) => setProcessingMsg(msg));
        if (result) {
          aiResponse = "Generated cinematic sequence:";
          videoUrl = result;
        } else {
          aiResponse = "WASO failed to render the cinematic sequence. Please ensure a paid API key is selected.";
        }
      } else if (mode === 'image') {
        const result = await gemini.generateImage(text);
        if (result) {
          aiResponse = "Generated visual frame:";
          imageUrl = result;
        } else {
          aiResponse = "WASO could not generate that frame.";
        }
      } else if (mode === 'audio') {
        const result = await gemini.tts(`[Artistic Audio Output]: ${text}`);
        if (result) {
          aiResponse = "Generated audio synthesis:";
          audioUrl = `data:audio/pcm;base64,${result}`;
        } else {
          aiResponse = "WASO could not synthesize that audio.";
        }
      } else if (file) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = e.target?.result?.toString().split(',')[1];
          if (base64) {
            const resp = await gemini.processMultimodal(text, base64, file.type);
            addAiMessage(resp || 'Failed to process file.');
          }
        };
        reader.readAsDataURL(file);
        return;
      } else {
        const history = currentSession?.messages.map(m => ({
          role: m.role === 'user' ? 'user' : 'model',
          parts: [{ text: m.content }]
        })) || [];
        aiResponse = await gemini.generateTextResponse(text, history);
      }

      if (aiResponse) addAiMessage(aiResponse, imageUrl, videoUrl, audioUrl);
    } catch (err) {
      console.error(err);
      addAiMessage("An unexpected error occurred.");
    } finally {
      setIsProcessing(false);
      setProcessingMsg('WASO Analysis Mode');
    }
  };

  const handleEditMessage = async (messageId: string, newText: string) => {
    if (!currentSessionId || !newText.trim() || isProcessing) return;

    setIsProcessing(true);
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        const msgIndex = s.messages.findIndex(m => m.id === messageId);
        if (msgIndex === -1) return s;

        const newMessages = s.messages.slice(0, msgIndex);
        return {
          ...s,
          messages: newMessages,
          updatedAt: Date.now()
        };
      }
      return s;
    }));

    await handleSendMessage(newText);
  };

  const addAiMessage = (content: string, imageUrl?: string, videoUrl?: string, audioUrl?: string) => {
    const aiMessage: Message = {
      id: Date.now().toString(),
      role: 'assistant',
      content,
      imageUrl,
      videoUrl,
      audioUrl,
      timestamp: Date.now(),
      type: videoUrl ? 'video' : audioUrl ? 'audio' : imageUrl ? 'image' : 'text',
    };

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, aiMessage], updatedAt: Date.now() };
      }
      return s;
    }));
  };

  const deleteSession = (id: string) => {
    setSessions(prev => prev.filter(s => s.id !== id));
    if (currentSessionId === id) {
      const remaining = sessions.filter(s => s.id !== id);
      if (remaining.length > 0) setCurrentSessionId(remaining[0].id);
      else createNewChat();
    }
  };

  return (
    <div className="flex flex-col h-screen w-full theme-gradient text-white overflow-hidden" style={{ height: 'var(--dvh)' }}>
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        sessions={sessions}
        currentSessionId={currentSessionId}
        onSelectSession={setCurrentSessionId}
        onNewChat={createNewChat}
        onDeleteSession={deleteSession}
      />

      <Navbar 
        onOpenSidebar={() => setIsSidebarOpen(true)} 
        activeTab={activeTab}
        onTabChange={setActiveTab}
        onNewChat={createNewChat}
      />

      <div className="flex-1 relative flex flex-col min-w-0 w-full overflow-hidden">
        <main className="flex-1 flex flex-col relative w-full h-full overflow-hidden">
          {activeTab === 'chat' ? (
            <div className="flex-1 flex flex-col w-full mx-auto px-1.5 md:px-4 relative overflow-hidden">
              {currentSession?.messages.length === 0 && !isProcessing && (
                <div className="absolute inset-0 flex flex-col items-center justify-center animate-fade-in text-center space-y-4 md:space-y-6 px-4 z-0 pointer-events-none">
                  <Avatar className="w-32 h-32 md:w-48 md:h-48 drop-shadow-[0_0_30px_rgba(0,180,216,0.3)] pointer-events-auto" />
                  <div className="pointer-events-auto">
                    <h1 className="text-3xl md:text-4xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-cyan-300">
                      Hey, I am WASO
                    </h1>
                    <p className="text-gray-400 max-w-sm md:text-lg mt-2">
                      I am ready to assist you in Bengali and English. Wasin created me.
                    </p>
                  </div>
                </div>
              )}

              <div className="flex-1 overflow-hidden relative flex flex-col w-full">
                <ChatArea 
                  messages={currentSession?.messages || []} 
                  isProcessing={isProcessing}
                  processingMsg={processingMsg}
                  onEditMessage={handleEditMessage}
                />
              </div>

              <div className="shrink-0 w-full max-w-5xl mx-auto">
                <InputArea 
                  onSendMessage={handleSendMessage} 
                  isProcessing={isProcessing}
                />
              </div>
            </div>
          ) : (
            <div className="flex-1 w-full max-w-4xl mx-auto px-4 h-full flex flex-col overflow-hidden">
              <LiveArea />
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

