import { ArrowUp, Mic, Image as ImageIcon, FileUp, X, Sparkles, Loader2, Video, Music } from 'lucide-react';

interface InputAreaProps {
  onSendMessage: (text: string, file?: File, mode?: 'text' | 'image' | 'video' | 'audio') => void;
  isProcessing: boolean;
}

const InputArea: React.FC<InputAreaProps> = ({ onSendMessage, isProcessing }) => {
  const [input, setInput] = useState('');
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [isListening, setIsListening] = useState(false);
  const [genMode, setGenMode] = useState<'text' | 'image' | 'video' | 'audio'>('text');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const recognitionRef = useRef<any>(null);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (SpeechRecognition) {
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = false;
      recognitionRef.current.lang = 'en-US';

      recognitionRef.current.onresult = (event: any) => {
        const transcript = event.results[0][0].transcript;
        setInput(prev => prev + (prev.endsWith(' ') || prev === '' ? '' : ' ') + transcript);
        setIsListening(false);
      };

      recognitionRef.current.onerror = () => setIsListening(false);
      recognitionRef.current.onend = () => setIsListening(false);
    }
  }, []);

  const handleSend = () => {
    if ((!input.trim() && !selectedFile) || isProcessing) return;
    onSendMessage(input, selectedFile || undefined, genMode);
    setInput('');
    setSelectedFile(null);
    setGenMode('text');
  };

  const toggleListen = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      try {
        recognitionRef.current?.start();
        setIsListening(true);
      } catch (e) {
        console.error("Speech recognition error", e);
      }
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setSelectedFile(e.target.files[0]);
    }
  };

  const toggleMode = (mode: 'image' | 'video' | 'audio') => {
    setGenMode(genMode === mode ? 'text' : mode);
  };

  const getPlaceholder = () => {
    switch (genMode) {
      case 'image': return "Describe a high-quality visual frame...";
      case 'video': return "Describe a cinematic animated visual sequence...";
      case 'audio': return "Describe the professional audio synthesis needed...";
      default: return "Collaborate with WASO...";
    }
  };

  const getModeStyles = () => {
    switch (genMode) {
      case 'image': return 'border-purple-500/40 ring-1 ring-purple-500/10';
      case 'video': return 'border-blue-500/40 ring-1 ring-blue-500/10';
      case 'audio': return 'border-emerald-500/40 ring-1 ring-emerald-500/10';
      default: return 'border-white/10 focus-within:border-[#00b4d8]/50';
    }
  };

  return (
    <div className="w-full flex flex-col items-center py-4 md:py-6 px-3 md:px-0 relative z-20">
      <div className="w-full max-w-4xl">
        {selectedFile && (
          <div className="mb-3 ml-2 flex items-center space-x-3 bg-blue-500/20 text-white px-4 py-1.5 rounded-full w-fit border border-blue-500/30 shadow-2xl animate-fade-in backdrop-blur-md">
