    const errorMessage = error?.message || String(error);

    if (
      errorMessage.includes("quota") || 
      errorMessage.includes("429") || 
      errorMessage.includes("Requested entity was not found") ||
      errorMessage.includes("API_KEY")
    ) {
      console.warn("Quota exceeded or invalid key detected. Opening key selection dialog...");
      await window.aistudio?.openSelectKey();
      return "Your API quota has been reached or the key is invalid. I have opened the key selection dialog. Please select a paid Google Cloud Project API key to continue.";
    }

    return "I encountered an error while processing your request. Please try again or check your connection.";
  }

  private async ensureApiKey() {
    const hasKey = await window.aistudio?.hasSelectedApiKey();
    if (!hasKey) {
      await window.aistudio?.openSelectKey();
    }
  }

