export class GeminiService {
  constructor() {}

  private async handleApiError(error: any) {
    console.error("Gemini API Error:", error);
    const errorMessage = error?.message || String(error);

    // If quota, auth fails, or permission is denied (403), prompt for a new key
    // 403 errors often mean the current project doesn't have access to Pro/Preview models or billing is missing
    if (
      errorMessage.includes("quota") || 
      errorMessage.includes("429") || 
      errorMessage.includes("Requested entity was not found") ||
      errorMessage.includes("API_KEY") ||
      errorMessage.includes("permission") ||
      errorMessage.includes("403")
    ) {
      console.warn("Permission denied or invalid key detected. Opening key selection dialog...");
      if (window.aistudio) {
        await window.aistudio.openSelectKey();
        return "I encountered a permission or quota issue. I have opened the key selection dialog. Please select a valid API key from a paid Google Cloud Project (with billing enabled) to continue.";
      }
    }

    return "I encountered an error while processing your request. This may be due to permission restrictions or quota limits. Please try again or select a different API key.";
  }

  private async ensureApiKey() {
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  }

  async generateTextResponse(prompt: string, history: { role: string; parts: { text: string }[] }[]) {
    try {
      await this.ensureApiKey();
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [...history, { role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          thinkingConfig: { thinkingBudget: 32768 }
        }
      });
      return response.text;
    } catch (error) {
      return await this.handleApiError(error);
    }
  }

  async generateImage(prompt: string) {
    try {
      await this.ensureApiKey();
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const enhancedPrompt = `A professional, high-end masterpiece, 8k resolution, cinematic lighting, ultra-detailed texture, masterpiece composition, photography by professional gear: ${prompt}`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [{ text: enhancedPrompt }]
        },
        config: {
          imageConfig: { 
            aspectRatio: "1:1", 
            imageSize: "1K" 
          }
        }
      });

      if (response.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            return `data:image/png;base64,${part.inlineData.data}`;
          }
        }
      }
      return null;
    } catch (error) {
      await this.handleApiError(error);
      return null;
    }
  }

  async processMultimodal(text: string, base64Data: string, mimeType: string) {
    try {
      await this.ensureApiKey();
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType } },
            { text: text || "Please analyze this file." }
          ]
        },
        config: {
          systemInstruction: SYSTEM_INSTRUCTION
        }
      });
      return response.text;
    } catch (error) {
      return await this.handleApiError(error);
    }
  }

  async tts(text: string): Promise<string | null> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Charon' } 
            }
          }
        }
      });
      return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || null;
    } catch (error) {
      console.error("TTS Error:", error);
      return null;
    }
  }

  connectLive(callbacks: {
    onopen: () => void;
    onmessage: (message: LiveServerMessage) => void;
    onerror: (e: ErrorEvent) => void;
    onclose: (e: CloseEvent) => void;
  }) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks,
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Charon' } },
        },
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });
  }
}

