    openSelectKey: () => Promise<void>;
  }

  interface Window {
    aistudio?: AIStudio;
  }
}

export class GeminiService {
  constructor() {}

  private async handleApiError(error: any): Promise<string> {
    console.error("Gemini API Error details:", error);
    const errorStr = JSON.stringify(error).toLowerCase();
    const errorMessage = (error?.message || String(error)).toLowerCase();

    // Detect Quota Exceeded (429) or Permission Denied (403)
    const isQuotaError = errorMessage.includes("quota") || errorMessage.includes("429") || errorStr.includes("resource_exhausted");
    const isPermissionError = errorMessage.includes("permission") || errorMessage.includes("403") || errorMessage.includes("not found");

    if (isQuotaError || isPermissionError) {
      console.warn("Quota or Permission issue detected. Triggering key selection...");

      if (window.aistudio) {
        // Platform requirement: Reset and prompt for key on these specific errors
        await window.aistudio.openSelectKey();

        if (isQuotaError) {
          return "### ⚠️ Quota Exceeded / কোটা শেষ হয়ে গেছে\n\nYour current API key has reached its usage limit. To continue using WASO's advanced Pro models, please **select an API key from a Paid Google Cloud Project** with billing enabled.\n\nআপনার বর্তমান API কোটা শেষ হয়ে গেছে। WASO-র উন্নত সার্ভিসগুলো ব্যবহার চালিয়ে যেতে একটি **পেইড গুগল ক্লাউড প্রজেক্ট** থেকে API কী সিলেক্ট করুন।\n\n[Learn about Gemini API Billing](https://ai.google.dev/gemini-api/docs/billing)";
        } else {
          return "### 🚫 Permission Denied / অ্যাক্সেস নেই\n\nWASO requires an API key with access to Pro models. Please ensure you have selected a valid key from a project that has the Gemini API enabled and supports high-tier models.\n\nWASO ব্যবহারের জন্য প্রো মডেল সাপোর্ট করে এমন একটি ভ্যালিড API কী প্রয়োজন। অনুগ্রহ করে আপনার প্রজেক্ট সেটিং চেক করুন।";
        }
      }
    }

    return "I encountered a neural interrupt while processing your request. Please try again or select a different API key if the issue persists.";
  }

  private async ensureApiKey() {
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
    }
  }

  async generateTextResponse(prompt: string, history: { role: string; parts: { text: string }[] }[]) {
    try {
      await this.ensureApiKey();
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [...history, { role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          thinkingConfig: { thinkingBudget: 32768 }
        }
      });
      return response.text;
    } catch (error) {
      return await this.handleApiError(error);
    }
  }

  async generateImage(prompt: string): Promise<{ url?: string; error?: string }> {
    try {
      await this.ensureApiKey();
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const enhancedPrompt = `A professional, high-end masterpiece, 8k resolution, cinematic lighting, ultra-detailed texture, masterpiece composition, photography by professional gear: ${prompt}`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-image-preview',
        contents: {
          parts: [{ text: enhancedPrompt }]
        },
        config: {
          imageConfig: { 
            aspectRatio: "1:1", 
            imageSize: "1K" 
          }
        }
      });

      if (response.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            return { url: `data:image/png;base64,${part.inlineData.data}` };
          }
        }
      }
      return { error: "Synthesis produced no visual output." };
    } catch (error) {
      const errorMsg = await this.handleApiError(error);
      return { error: errorMsg };
    }
  }

  async processMultimodal(text: string, base64Data: string, mimeType: string) {
    try {
      await this.ensureApiKey();
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType } },
            { text: text || "Please analyze this file." }
          ]
        },
        config: {
          systemInstruction: SYSTEM_INSTRUCTION
        }
      });
      return response.text;
    } catch (error) {
      return await this.handleApiError(error);
    }
  }

  async tts(text: string): Promise<string | null> {
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Charon' } 
            }
          }
        }
      });
      return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || null;
    } catch (error) {
      console.error("TTS Error:", error);
      return null;
    }
  }

  connectLive(callbacks: {
    onopen: () => void;
    onmessage: (message: LiveServerMessage) => void;
    onerror: (e: ErrorEvent) => void;
    onclose: (e: CloseEvent) => void;
  }) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    return ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks,
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Charon' } },
        },
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });
  }
}

export const gemini = new GeminiService();

export function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import ChatArea from './components/ChatArea';
import InputArea from './components/InputArea';
import LiveArea from './components/LiveArea';
import Avatar from './components/Avatar';
import { ChatSession, Message } from './types';
import { gemini } from './services/geminiService';

const App: React.FC = () => {
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'chat' | 'live'>('chat');
  const [isProcessing, setIsProcessing] = useState(false);
  const [processingMsg, setProcessingMsg] = useState('WASO Analysis Mode');

  const currentSession = sessions.find(s => s.id === currentSessionId);

  useEffect(() => {
    const saved = localStorage.getItem('waso_chats');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        setSessions(parsed);
        if (parsed.length > 0) setCurrentSessionId(parsed[0].id);
      } catch (e) {
        createNewChat();
      }
    } else {
      createNewChat();
    }
  }, []);

  useEffect(() => {
    if (sessions.length > 0) {
      localStorage.setItem('waso_chats', JSON.stringify(sessions));
    }
  }, [sessions]);

  const createNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Chat',
      messages: [],
      updatedAt: Date.now(),
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    setIsSidebarOpen(false);
    setActiveTab('chat');
  };

  const handleSendMessage = async (text: string, file?: File, mode: 'text' | 'image' = 'text') => {
    if (!currentSessionId || (!text && !file)) return;

    setIsProcessing(true);
    setProcessingMsg(mode === 'image' ? 'WASO Image Synthesis' : 'WASO Analysis Mode');

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: text,
      timestamp: Date.now(),
      type: file ? (file.type.startsWith('image/') ? 'image' : 'file') : (mode as any),
    };

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return {
          ...s,
          messages: [...s.messages, userMessage],
          title: s.messages.length === 0 ? (text.slice(0, 30) || (mode === 'image' ? 'Image Generation' : 'Interaction')) : s.title,
          updatedAt: Date.now()
        };
      }
      return s;
    }));

    try {
      let aiResponse: string | null = '';
      let imageUrl: string | undefined;

      if (mode === 'image') {
        setProcessingMsg('Synthesizing Visual Latents...');
        const result = await gemini.generateImage(text);
        if (result.url) {
          aiResponse = "Generated visual masterpiece:";
          imageUrl = result.url;
        } else {
          aiResponse = result.error || "WASO was unable to complete the visual synthesis.";
        }
      } else if (file) {
        const reader = new FileReader();
        reader.onload = async (e) => {
          const base64 = e.target?.result?.toString().split(',')[1];
          if (base64) {
            const resp = await gemini.processMultimodal(text, base64, file.type);
            addAiMessage(resp || 'Failed to process file.');
          }
        };
        reader.readAsDataURL(file);
        return;
      } else {
        const history = currentSession?.messages.map(m => ({
          role: m.role === 'user' ? 'user' : 'model',
          parts: [{ text: m.content }]
        })) || [];
        aiResponse = await gemini.generateTextResponse(text, history);
      }

      if (aiResponse) addAiMessage(aiResponse, imageUrl);
    } catch (err) {
      console.error(err);
      addAiMessage("An unexpected neural interrupt occurred during synthesis.");
    } finally {
      setIsProcessing(false);
      setProcessingMsg('WASO Analysis Mode');
    }
  };

  const handleEditMessage = async (messageId: string, newText: string) => {
    if (!currentSessionId || !newText.trim() || isProcessing) return;

    setIsProcessing(true);
    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        const msgIndex = s.messages.findIndex(m => m.id === messageId);
        if (msgIndex === -1) return s;

        const newMessages = s.messages.slice(0, msgIndex);
        return {
          ...s,
          messages: newMessages,
          updatedAt: Date.now()
        };
      }
      return s;
    }));

    await handleSendMessage(newText);
  };

  const addAiMessage = (content: string, imageUrl?: string) => {
    const aiMessage: Message = {
      id: Date.now().toString(),
      role: 'assistant',
      content,
      imageUrl,
      timestamp: Date.now(),
      type: imageUrl ? 'image' : 'text',
    };

    setSessions(prev => prev.map(s => {
      if (s.id === currentSessionId) {
        return { ...s, messages: [...s.messages, aiMessage], updatedAt: Date.now() };
      }
      return s;
    }));
  };

  const deleteSession = (id: string) => {
    setSessions(prev => prev.filter(s => s.id !== id));
    if (currentSessionId === id) {
      const remaining = sessions.filter(s => s.id !== id);
      if (remaining.length > 0) setCurrentSessionId(remaining[0].id);
      else createNewChat();
    }
  };

  return (
    <div className="flex flex-col h-screen w-full theme-gradient text-white overflow-hidden" style={{ height: 'var(--dvh)' }}>
      <Sidebar 
        isOpen={isSidebarOpen} 
        onClose={() => setIsSidebarOpen(false)} 
        sessions={sessions}
        currentSessionId={currentSessionId}
        onSelectSession={setCurrentSessionId}
        onNewChat={createNewChat}
        onDeleteSession={deleteSession}
      />

      <Navbar 
        onOpenSidebar={() => setIsSidebarOpen(true)} 
        activeTab={activeTab}
        onTabChange={setActiveTab}
        onNewChat={createNewChat}
      />

      <div className="flex-1 relative flex flex-col min-w-0 w-full overflow-hidden">
        <main className="flex-1 flex flex-col relative w-full h-full overflow-hidden">
          {activeTab === 'chat' ? (
            <div className="flex-1 flex flex-col w-full mx-auto px-1.5 md:px-4 relative overflow-hidden">
              {currentSession?.messages.length === 0 && !isProcessing && (
                <div className="absolute inset-0 flex flex-col items-center justify-center animate-fade-in text-center space-y-4 md:space-y-6 px-4 z-0 pointer-events-none">
                  <Avatar className="w-32 h-32 md:w-48 md:h-48 drop-shadow-[0_0_30px_rgba(0,180,216,0.3)] pointer-events-auto" />
                  <div className="pointer-events-auto">
                    <h1 className="text-3xl md:text-4xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-cyan-300">
                      Hey, I am WASO
                    </h1>
                    <p className="text-gray-400 max-w-sm md:text-lg mt-2">
                      Professional AI Assistant. I can generate high-end visual masterpieces. Wasin created me.
                    </p>
                  </div>
                </div>
              )}

              <div className="flex-1 overflow-hidden relative flex flex-col w-full">
                <ChatArea 
                  messages={currentSession?.messages || []} 
                  isProcessing={isProcessing}
                  processingMsg={processingMsg}
                  onEditMessage={handleEditMessage}
                />
              </div>

              <div className="shrink-0 w-full max-w-5xl mx-auto">
                <InputArea 
                  onSendMessage={handleSendMessage} 
                  isProcessing={isProcessing}
                />
              </div>
            </div>
          ) : (
            <div className="flex-1 w-full max-w-4xl mx-auto px-4 h-full flex flex-col overflow-hidden">
              <LiveArea />
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;
